package dev.sargunv.mobilitydata.gofs.v1

import kotlinx.coroutines.test.runTest

class DocsSnippet {
  fun example() = runTest {
    // --8<-- [start:example]
    GofsV1Client().use { gbfs -> // (1)!
      val manifest =
        gbfs
          .getSystemManifest( // (2)!
            discoveryUrl = "<discovery url>"
          )
          .data

      context(manifest.getService("en")) { // (3)!
