        val waitTimes = // (6)!
          gbfs.getWaitTimes(pickupLat = 41.8781, pickupLon = -87.6298).data

        println("\nWait Times:")
        waitTimes.forEach { waitTime ->
          println("  - Brand ${waitTime.brandId}: ${waitTime.waitTime} seconds")
        }
      }
    }
    // --8<-- [end:example]
  }
}

